const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const headers = {
  apikey: SUPABASE_KEY,
  Authorization: "Bearer " + SUPABASE_KEY,
  "Content-Type": "application/json"
};

// 1. Get caller user IDs
const usersResp = await this.helpers.httpRequest({
  method: "GET",
  url: SUPABASE_URL + "/rest/v1/users?role=eq.caller&select=id",
  headers
});
const callerIds = usersResp.map(u => u.id);
if (callerIds.length === 0) return [];

// 2. Get calls: duration>20, has recording, belongs to caller
const callerFilter = "user_id=in.(" + callerIds.join(",") + ")";
const callsResp = await this.helpers.httpRequest({
  method: "GET",
  url: SUPABASE_URL + "/rest/v1/calls?select=id,close_call_id,recording_url,user_id,lead_id,duration,close_created_at,close_lead_id&duration=gt.20&recording_url=not.is.null&" + callerFilter + "&order=close_created_at.desc&limit=50",
  headers
});
if (callsResp.length === 0) return [];

// 3. Filter out calls that already have an analysis
const callIds = callsResp.map(c => c.id);
const analysesResp = await this.helpers.httpRequest({
  method: "GET",
  url: SUPABASE_URL + "/rest/v1/coldcall_analyses?select=call_id&call_id=in.(" + callIds.join(",") + ")",
  headers
});
const processedIds = new Set(analysesResp.map(a => a.call_id));

const unprocessed = callsResp.filter(c => !processedIds.has(c.id));
return unprocessed.map(c => ({ json: c }));

const CLOSE_AUTH = $env.CLOSE_API_KEY;

const items = $input.all();
const results = [];

for (const item of items) {
  const call = item.json;
  const recordingUrl = call.recording_url;

  if (!recordingUrl) {
    results.push({ json: { ...call, directUrl: null, error: 'No recording URL' } });
    continue;
  }

  try {
    const headResp = await this.helpers.httpRequest({
      method: 'HEAD',
      url: recordingUrl,
      headers: { 'Authorization': CLOSE_AUTH },
      disableFollowRedirect: true,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true
    });

    const loc = (headResp.headers || {}).location || (headResp.headers || {}).Location;
    results.push({ json: { ...call, directUrl: loc || recordingUrl } });
  } catch (e) {
    results.push({ json: { ...call, directUrl: recordingUrl, resolveError: e.message } });
  }
}

return results;

const call = $('Loop Over Calls').first().json;
const transcriptText = $('Whisper Transcribe').first().json.text || null;
const gptRaw = $('GPT-4o Mini Analyse').first().json;

let analysis = {};
try {
  const content = gptRaw.choices?.[0]?.message?.content;
  analysis = content ? JSON.parse(content) : {};
} catch (e) {
  analysis = {};
}

const einwaende = analysis.einwaende || [];
const score = analysis.gespraechsqualitaet?.score ?? null;
const scoreReasoning = analysis.gespraechsqualitaet?.reasoning || null;

return [{
  json: {
    call_id: call.id,
    close_call_id: call.close_call_id,
    transcript: transcriptText,
    ai_summary: analysis.zusammenfassung || null,
    decision_maker_reached: analysis.entscheider_erreicht ?? null,
    objections: einwaende,
    score: score,
    score_reasoning: scoreReasoning,
    call_result: analysis.ergebnis || null,
    synced_at: new Date().toISOString()
  }
}];
